import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Button, icon, Select, Textarea, Input } from 'decantr/components';

code.example:
function MaintenanceTicketCreate({ tenant, onSubmit }) {
  const { div, form, h1, h2, label, p, span } = tags;
  const [category, setCategory] = createSignal('');
  const [priority, setPriority] = createSignal('medium');
  const [description, setDescription] = createSignal('');
  const [photos, setPhotos] = createSignal([]);
  const [availability, setAvailability] = createSignal('');

  const handlePhotoUpload = (e) => {
    const files = Array.from(e.target.files);
    const urls = files.map(f => URL.createObjectURL(f));
    setPhotos([...photos(), ...urls]);
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    onSubmit({ category: category(), priority: priority(), description: description(), photos: photos(), availability: availability() });
  };

  return div({ class: css('estate-card _p6') },
    h1({ class: css('_heading3 _mb2') }, 'Submit Maintenance Request'),
    p({ class: css('_fgmuted _mb6') }, `For ${tenant.propertyName} - Unit ${tenant.unitNumber}`),
    form({ class: css('_flex _col _gap4'), onsubmit: handleSubmit },
      div({},
        label({ class: css('_textsm _font500 _mb1 _block') }, 'Issue Category *'),
        Select({ value: category(), onchange: e => setCategory(e.target.value), required: true },
          tags.option({ value: '' }, 'Select a category...'),
          tags.option({ value: 'plumbing' }, 'Plumbing'),
          tags.option({ value: 'electrical' }, 'Electrical'),
          tags.option({ value: 'hvac' }, 'Heating / Cooling'),
          tags.option({ value: 'appliance' }, 'Appliance'),
          tags.option({ value: 'structural' }, 'Structural / Walls / Floors'),
          tags.option({ value: 'pest' }, 'Pest Control'),
          tags.option({ value: 'other' }, 'Other')
        )
      ),
      div({},
        label({ class: css('_textsm _font500 _mb2 _block') }, 'Priority Level'),
        div({ class: css('_flex _gap2') },
          Button({ type: 'button', variant: priority() === 'low' ? 'default' : 'outline', size: 'sm', onclick: () => setPriority('low') }, 'Low'),
          Button({ type: 'button', variant: priority() === 'medium' ? 'default' : 'outline', size: 'sm', onclick: () => setPriority('medium') }, 'Medium'),
          Button({ type: 'button', variant: priority() === 'high' ? 'default' : 'outline', size: 'sm', onclick: () => setPriority('high') }, 'High'),
          Button({ type: 'button', variant: priority() === 'emergency' ? 'default' : 'outline', size: 'sm', onclick: () => setPriority('emergency'), class: css('_bgDanger/10 _hoverBgDanger/20') }, icon('alert-triangle'), 'Emergency')
        )
      ),
      div({},
        label({ class: css('_textsm _font500 _mb1 _block') }, 'Describe the Issue *'),
        Textarea({ value: description(), oninput: e => setDescription(e.target.value), placeholder: 'Please describe the problem in detail...', rows: 4, required: true })
      ),
      div({},
        label({ class: css('_textsm _font500 _mb2 _block') }, 'Photos (optional)'),
        div({ class: css('_flex _gap2 _flexwrap _mb2') },
          ...photos().map((url, i) => div({ class: css('_relative _w20 _h20') },
            tags.img({ src: url, class: css('_wfull _hfull _objcover _r1') }),
            Button({ variant: 'ghost', size: 'icon', class: css('_absolute _top1 _right1 _bgSurface'), onclick: () => setPhotos(photos().filter((_, j) => j !== i)) }, icon('x', { size: '12' }))
          ))
        ),
        label({ class: css('_flex _aic _jcc _gap2 _p6 _border _borderDashed _r2 _cursor[pointer] _hoverBgSurfaceRaised _trans') },
          icon('camera'),
          span({}, 'Add Photos'),
          Input({ type: 'file', accept: 'image/*', multiple: true, onchange: handlePhotoUpload, class: css('_hidden') })
        )
      ),
      div({},
        label({ class: css('_textsm _font500 _mb1 _block') }, 'Access Availability'),
        Textarea({ value: availability(), oninput: e => setAvailability(e.target.value), placeholder: 'When can we access your unit? e.g., "Weekdays 9am-5pm" or "Anytime with 24hr notice"', rows: 2 })
      ),
      Button({ type: 'submit', variant: 'primary', class: css('_mt4') }, 'Submit Request')
    )
  );
}

