import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { link } from 'decantr/router';
import { Button, icon, Badge, Avatar } from 'decantr/components';

code.example:
function MaintenanceTicketView({ ticket }) {
  const { div, h1, h2, p, span, img, time } = tags;
  const priorityColor = ticket.priority === 'emergency' ? 'danger' : ticket.priority === 'high' ? 'warning' : 'default';
  const statusColor = ticket.status === 'completed' || ticket.status === 'closed' ? 'success' : ticket.status === 'in-progress' ? 'warning' : 'default';

  return div({ class: css('_flex _col _gap6') },
    div({ class: css('_flex _aic _gap2 _mb2') },
      link({ href: '/maintenance', class: css('_fgmuted _hoverFg') }, icon('arrow-left'), ' Back')
    ),
    div({ class: css('estate-card _p6') },
      div({ class: css('_flex _jcsb _aic _mb6') },
        div({},
          div({ class: css('_flex _aic _gap3 _mb1') },
            h1({ class: css('_heading4') }, `Ticket #${ticket.id}`),
            Badge({ variant: statusColor }, ticket.status)
          ),
          p({ class: css('_textsm _fgmuted') }, `${ticket.propertyName} - Unit ${ticket.unitNumber}`)
        ),
        div({ class: css('_flex _gap2') },
          Badge({ variant: 'outline' }, ticket.category),
          Badge({ variant: priorityColor }, ticket.priority)
        )
      ),
      div({ class: css('_mb6') },
        h2({ class: css('_heading6 _mb2') }, 'Description'),
        p({ class: css('_textsm _whitespace[pre-wrap]') }, ticket.description)
      ),
      ticket.photos?.length > 0 ? div({ class: css('_mb6') },
        h2({ class: css('_heading6 _mb2') }, 'Photos'),
        div({ class: css('_flex _gap2 _flexwrap') },
          ...ticket.photos.map(url => img({ src: url, class: css('_w32 _h24 _objcover _r1 _cursor[pointer]'), onclick: () => window.open(url) }))
        )
      ) : null,
      ticket.assignee ? div({ class: css('_mb6') },
        h2({ class: css('_heading6 _mb2') }, 'Assigned To'),
        div({ class: css('_flex _aic _gap3') },
          Avatar({ src: ticket.assignee.avatar, alt: ticket.assignee.name, size: 'sm' }),
          div({},
            span({ class: css('_font500 _block') }, ticket.assignee.name),
            span({ class: css('_textsm _fgmuted') }, ticket.assignee.company || 'Staff')
          )
        )
      ) : null,
      div({ class: css('_mb6') },
        h2({ class: css('_heading6 _mb3') }, 'Timeline'),
        div({ class: css('_flex _col _gap3 _pl4 _borderL[2px]') },
          ...ticket.timeline.map(event =>
            div({ class: css('_relative') },
              div({ class: css('_absolute _left[-21px] _top1 _w2 _h2 _r[50%] _bgPrimary') }),
              div({ class: css('_flex _jcsb _aic') },
                span({ class: css('_font500') }, event.action),
                time({ class: css('_textsm _fgmuted') }, new Date(event.date).toLocaleString())
              ),
              event.note ? p({ class: css('_textsm _fgmuted _mt1') }, event.note) : null
            )
          )
        )
      ),
      div({ class: css('_flex _gap2 _pt4 _borderT') },
        Button({ variant: 'outline' }, icon('message-circle'), 'Add Comment'),
        !ticket.assignee ? Button({ variant: 'outline' }, icon('user-plus'), 'Assign') : null,
        ticket.status !== 'completed' && ticket.status !== 'closed' ? Button({ variant: 'primary' }, icon('check'), 'Mark Complete') : null
      )
    )
  );
}

