function RecentTickets({ tickets }) {
  const { div, span } = tags;
  const statusColor = (status) => status === 'completed' ? 'success' : status === 'in-progress' ? 'warning' : 'default';

  return div({ class: css('estate-card _p4') },
    div({ class: css('_flex _jcsb _aic _mb3') },
      span({ class: css('_heading6') }, 'Recent Maintenance'),
      link({ href: '/maintenance', class: css('_textsm _fgPrimary') }, 'View All')
    ),
    div({ class: css('_flex _col _gap2') },
      ...tickets.slice(0, 5).map(t =>
        link({ href: `/maintenance/${t.id}`, class: css('_flex _jcsb _aic _p2 _r1 _hoverBgSurfaceRaised _trans') },
          div({},
            span({ class: css('_textsm _font500 _block') }, `#${t.id} - ${t.category}`),
            span({ class: css('_textxs _fgmuted') }, t.unitNumber ? `Unit ${t.unitNumber}` : t.propertyName)
          ),
          Badge({ variant: statusColor(t.status), size: 'sm' }, t.status)
        )
      )
    )
  );
}

